onClick:
{{
  (() => {
    // Executa a query injetando os parâmetros de forma isolada e segura
    Query_Atualizar_Geral.run({
      data_e_hora_denuncia: Input_data_e_hora_denuncia.text,
      Telefone: Telefone_animal.text,
      Email: email_animal.text,
      Nome_Denunciante: Denunciante_animal.text,
      Nome_Agressor: Agressor_animal.text,
      Nome_Testemunha: Testemunha_animal.text,
      Localizacao: Localizacao_animal.text,
      Resposta_Denunciante: Resposta_Denunciante_animal.text,
      data_reg_animal: data_reg_animal.text,
      hora_reg_animal: hora_reg_animal.text,
      classificacao: classificacao.text,
      Descricao: Text_den_animal.text,
      Num_Denuncia: select_altera_cad_animal.selectedOptionValue
    })
    .then(() => {
      // Recarrega as duas queries do seu banco para atualizar a tela
      Tabela_Cad_Animal.run(); 
      Query_Buscar_Denuncia.run();

      // Alerta de sucesso
      showAlert('Alterações salvas com sucesso!', 'success');

      // Lista de campos para limpar
      const camposDoModal = [
        "Input_data_e_hora_denuncia",
        "Telefone_animal",
        "email_animal",
        "Denunciante_animal",
        "Agressor_animal",
        "Testemunha_animal",
        "Localizacao_animal",
        "Resposta_Denunciante_animal",
        "data_reg_animal",
        "hora_reg_animal",
        "classificacao",
        "Text_den_animal"
      ];

      // Executa a limpeza individual de forma assíncrona
      camposDoModal.forEach(async (campo) => {
        await resetWidget(campo, true);
      });

      // Fecha o modal de edição automaticamente
      closeModal("Modal_Editar_Cad_Animal");
    })
    .catch((err) => {
      showAlert('Erro ao processar atualizações: ' + err.message, 'error');
    });
  })()
}}
